      "type": "activity",
      "title": "Construct the Square Root Spiral",
      "unit_name": "Number System",
      "chapter_name": "Number System",
      "details": "Students will construct a square root spiral to visualize irrational numbers."
    },
    {
      "type": "activity",
      "title": "Visualise Algebraic Identities using Geometrical Models",
      "unit_name": "Algebra",
      "chapter_name": "Exploring Algebraic Identities",
      "details": "Students will use geometric models and algebra tiles to visualise identities, factorisation of quadratic expressions, and simplification of rational expressions."
    },
    {
      "type": "activity",
      "title": "Tower of Hanoi Puzzle",
      "unit_name": "Algebra",
      "chapter_name": "Sequences and Progressions",
      "details": "Students will solve the Tower of Hanoi puzzle to understand recursive rules in sequences."
    },
    {
      "type": "activity",
      "title": "Represent a Floor Plan on a Grid using Coordinates",
      "unit_name": "Coordinate Geometry",
      "chapter_name": "Coordinate Geometry",
      "details": "Students will specify locations and positions of points relative to each other using coordinates."
    },
    {
      "type": "activity",
      "title": "Constructing a Square with a Given Side (Sulbasutras)",
      "unit_name": "Geometry",
      "chapter_name": "Axioms and Postulates",
      "details": "Students will describe the construction of a square as given in Baudhayana's Sulbasutras."
    },
    {
      "type": "activity",
      "title": "Drawing, Measurement, and Paper Manipulation Activities for 4-gons",
      "unit_name": "Geometry",
      "chapter_name": "4-gons (Quadrilaterals)",
      "details": "Students will engage in drawing, measurement, and paper manipulation to discover geometric patterns involving triangles and quadrilaterals."
    },
    {
      "type": "activity",
      "title": "Geometric Constructions using Axioms",
      "unit_name": "Geometry",
      "chapter_name": "Axioms and Postulates",
      "details": "Students will construct bisectors of line segments, angles, triangles, and other polygons satisfying given constraints."
    },
    {
      "type": "activity",
      "title": "Squaring a Rectangle (Baudhayana's Sulbasutras)",
      "unit_name": "Mensuration",
      "chapter_name": "Area and Perimeter",
      "details": "Students will explore the classical problem of 'squaring' a given shape using methods from ancient civilisations."
    },
    {
      "type": "activity",
      "title": "Empirical Probability Experiments",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Introduction to Probability",
      "details": "Students will perform experiments to estimate the empirical probability of events."
    }
  ],
  "projects": [
    {
      "title": "Mathematics Laboratory Activities (Prescribed Books)",
      "unit_name": "All Units",
      "chapter_name": "General Practical Work",
      "details": "Lab activities to be done from the prescribed books: 'Guidelines for Mathematics Laboratory in Schools, class IX' and 'Laboratory Manual - Mathematics, secondary stage'. Includes graphing data, constructing geometric shapes, and measuring 3D objects."
    }
  ],
  "practicals": [
    {
      "title": "Lab Practical Assessment",
      "unit_name": "All Units",
      "chapter_name": "General Practical Work",
      "details": "Assessment component worth 5 marks involving lab activities from prescribed books, focusing on graphical representation of data, geometric constructions (bisectors, triangles), and calculation of surface areas/volumes."
    }
  ]
